#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Council probe 2 (exit-0-safe): soften idle-txn timeout to 120s (still kills the
multi-min stuck txns, not slow-but-valid workers); verify enrichment gross rate holds;
inspect QA auditor deployment + rate so we can scale it (the new bottleneck)."""
import os,sys,json,time,subprocess
def sh(c,t=25):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception: return "ERR"
def psql(q,t=18):
    r=subprocess.run(["sudo","-u","postgres","psql","tuanichat_atlas","-tAc",q],capture_output=True,text=True,timeout=t)
    return (r.stdout.strip().split('\n')[-1] if r.returncode==0 and r.stdout.strip() else "ERR")
out={"kind":"council2","ts":int(time.time())}
try:
    # soften idle timeout 45 -> 120s
    out["idle_120"]=psql("ALTER DATABASE tuanichat_atlas SET idle_in_transaction_session_timeout='120s'"); psql("SELECT pg_reload_conf()")
    out["cur_settings"]=psql("SELECT 'lock='||current_setting('lock_timeout')||' idle='||current_setting('idle_in_transaction_session_timeout')")
    # enrichment gross via claimed->done movement over 40s (count rows that LEFT pending)
    p0=psql("SELECT count(*) FILTER (WHERE status='done') FROM atlas.enrich_queue"); t0=time.time()
    time.sleep(40)
    p1=psql("SELECT count(*) FILTER (WHERE status='done') FROM atlas.enrich_queue"); t1=time.time()
    out["done_delta_per_min"]=None
    try: out["done_delta_per_min"]=round((int(p1)-int(p0))*60.0/(t1-t0),1)
    except Exception: pass
    out["active_now"]=psql("SELECT count(*) FROM pg_stat_activity WHERE state='active'")
    out["enrich_pool_busy"]=psql("SELECT count(*) FROM pg_stat_activity WHERE application_name ILIKE '%enrich%' OR query ILIKE '%enrich_queue%'")
    # QA auditor deployment + rate
    out["qa_units"]=sh("systemctl list-unit-files --no-legend 2>/dev/null | awk '{print $1}' | grep -iE 'qa|audit' | head")
    out["qa_active"]=sh("systemctl list-units 'atlas-qa*' --no-legend --plain 2>/dev/null | awk '{print $1,$4}' | head")
    out["qa_exec"]=sh("systemctl cat atlas-qa-auditor.service atlas-qa.service 2>/dev/null | grep -iE 'ExecStart|Environment|CONCURRENCY|BATCH' | head")
    # QA rate: checked-count delta — qa writes qa_status; count graded over the 40s window already elapsed
    out["qa_checked_now"]=psql("SELECT count(*) FILTER (WHERE qa_status IS NOT NULL AND qa_status<>'') FROM atlas.business")
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/council2.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"council2","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(6):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
